from qiskit.quantum_info import SparsePauliOp

# "Z on qubit index 0" of a 3-qubit operator
op = SparsePauliOp.from_sparse_list([("Z", [0], 1.0)], num_qubits=3)
observed = str(op.paulis[0])

candidates = {"A": "ZII", "B": "IZI", "C": "ZZZ", "D": "IIZ"}
evidence = {}
proven = []
for k, val in candidates.items():
    m = (observed == val)
    evidence[k] = f"from_sparse_list([('Z',[0],1.0)], num_qubits=3) -> '{observed}'; option claims '{val}' -> match={m}"
    if m:
        proven.append(k)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"label": observed}})
